+<div class="file-drop-zone @(_isDragOver ? "drag-over" : "")"
+     @ondragover="HandleDragOver"
+     @ondragover:preventDefault
+     @ondragleave="HandleDragLeave"
+     @ondrop="HandleDrop"
+     @ondrop:preventDefault>
+    <p>Drag and drop files here</p>
+    <InputFile OnChange="HandleFileSelection" multiple style="display:none" />
+</div>
+
+@if (_fileEntries.Count > 0)
+{
+    <ul class="file-list">
+        @foreach (var entry in _fileEntries)
+        {
+            <li class="file-entry @(entry.IsOversize ? "file-error" : "")">
+                @if (entry.IsOversize)
+                {
+                    <span class="error-message">@entry.Name — File exceeds 10MB limit (@FormatSize(entry.Size))</span>
+                }
+                else
+                {
+                    <span>@entry.Name — @FormatSize(entry.Size) — @entry.Type</span>
+                }
+                <button class="remove-btn" @onclick="() => RemoveFile(entry)">Remove</button>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    [Parameter]
+    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }
+
+    private bool _isDragOver;
+    private readonly List<FileEntry> _fileEntries = new();
+
+    private const long MaxFileSize = 10 * 1024 * 1024; // 10MB
+
+    private void HandleDragOver() => _isDragOver = true;
+    private void HandleDragLeave() => _isDragOver = false;
+
+    private async Task HandleDrop(DragEventArgs e)
+    {
+        _isDragOver = false;
+        // Drop is handled via InputFile; DragEventArgs doesn't expose file data in Blazor.
+        // Users see the InputFile as a fallback. For true drag-drop we use JS interop below.
+    }
+
+    private async Task HandleFileSelection(InputFileChangeEventArgs e)
+    {
+        foreach (var file in e.GetMultipleFiles(100))
+        {
+            _fileEntries.Add(new FileEntry(file.Name, file.Size, file.ContentType, file.Size > MaxFileSize));
+        }
+        await NotifyParent();
+    }
+
+    private async Task RemoveFile(FileEntry entry)
+    {
+        _fileEntries.Remove(entry);
+        await NotifyParent();
+    }
+
+    private async Task NotifyParent()
+    {
+        var accepted = _fileEntries
+            .Where(f => !f.IsOversize)
+            .Select(f => new FileInfo(f.Name, f.Size, f.Type))
+            .ToList();
+        await OnFilesChanged.InvokeAsync(accepted);
+    }
+
+    private static string FormatSize(long bytes) => bytes switch
+    {
+        < 1024 => $"{bytes} B",
+        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
+        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
+    };
+
+    private record FileEntry(string Name, long Size, string Type, bool IsOversize);
+}
